// db.js — طبقة تخزين البيانات، بتستخدم Neon Postgres (serverless) بدل ملف db.json المحلي
// السبب: لو الموقع اتنشر على منصة serverless زي Vercel، أي حاجة تتكتب في ملف محلي
// بتتمسح تاني (الـ filesystem مؤقت وبيتصفر بين الطلبات) — فالبيانات (مشاريع، طلبات،
// تقييمات...) لازم تتخزن في قاعدة بيانات حقيقية بره السيرفر نفسه.
require('dotenv').config();
const { neon } = require('@neondatabase/serverless');
const bcrypt = require('bcryptjs');
const crypto = require('crypto');

if (!process.env.DATABASE_URL) {
  console.error('❌ DATABASE_URL مش موجود في .env — لازم تحطه (من Neon) عشان البيانات تتخزن صح.');
}
// لو الرابط مش موجود، بنستخدم قيمة وهمية عشان السيرفر يقدر يبدأ (الصفحات الثابتة تفضل شغالة)
// وأي محاولة فعلية تلمس قاعدة البيانات هي اللي هتفشل برسالة واضحة، مش السيرفر كله من الأول
const sql = neon(process.env.DATABASE_URL || 'postgresql://user:pass@host.neon.tech/db?sslmode=require');

let _tablesReady = null;
async function ensureTables() {
  if (_tablesReady) return _tablesReady;
  _tablesReady = (async () => {
    await sql`CREATE TABLE IF NOT EXISTS app_state (
      id INT PRIMARY KEY DEFAULT 1,
      data JSONB NOT NULL,
      updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
    )`;
    // نسخة احتياطية يومية بسيطة — بتتحدث تلقائي مع كل تعديل في نفس اليوم
    await sql`CREATE TABLE IF NOT EXISTS app_backups (
      backup_date DATE PRIMARY KEY,
      data JSONB NOT NULL,
      created_at TIMESTAMPTZ NOT NULL DEFAULT now()
    )`;
    // تخزين أكواد الـ OTP هنا بدل متغير في الذاكرة — عشان لو الطلب اللي بيبعت الكود
    // والطلب اللي بيتحقق منه اتنفذوا على نسختين مختلفتين من السيرفر (بيحصل على Vercel)
    // يفضلوا شايفين نفس الكود
    await sql`CREATE TABLE IF NOT EXISTS otp_store (
      email TEXT PRIMARY KEY,
      otp TEXT NOT NULL,
      expires_at TIMESTAMPTZ NOT NULL,
      attempts INT NOT NULL DEFAULT 1
    )`;
  })();
  return _tablesReady;
}

