async function readDB() {
  await ensureTables();
  const rows = await sql`SELECT data FROM app_state WHERE id = 1`;
  if (!rows.length) {
    const def = buildDefaultData();
    await sql`INSERT INTO app_state (id, data) VALUES (1, ${JSON.stringify(def)}::jsonb)
              ON CONFLICT (id) DO NOTHING`;
    return def;
  }
  return rows[0].data;
}

async function writeDB(data) {
  await ensureTables();
  await sql`INSERT INTO app_state (id, data, updated_at) VALUES (1, ${JSON.stringify(data)}::jsonb, now())
            ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data, updated_at = now()`;
  // نسخة احتياطية يومية (upsert بتاريخ اليوم) — بتحل محل الـ setInterval القديم
  // اللي مكانش هيشتغل على سيرفرات serverless مالهاش عملية شغالة باستمرار
  const today = new Date().toISOString().split('T')[0];
  sql`INSERT INTO app_backups (backup_date, data) VALUES (${today}, ${JSON.stringify(data)}::jsonb)
      ON CONFLICT (backup_date) DO UPDATE SET data = EXCLUDED.data, created_at = now()`
    .catch(e => console.error('Backup write failed:', e.message));
  // امسح النسخ الاحتياطية الأقدم من 14 يوم (تنضيف بسيط، مش لازم ننتظره)
  sql`DELETE FROM app_backups WHERE backup_date < (CURRENT_DATE - INTERVAL '14 days')`
    .catch(() => {});
}

async function listBackups() {
  await ensureTables();
  return sql`SELECT backup_date, created_at FROM app_backups ORDER BY backup_date DESC LIMIT 14`;
}

async function restoreBackup(date) {
  await ensureTables();
  const rows = await sql`SELECT data FROM app_backups WHERE backup_date = ${date}`;
  if (!rows.length) return null;
  await writeDB(rows[0].data);
  return rows[0].data;
}

async function getOtp(email) {
  await ensureTables();
  const rows = await sql`SELECT otp, expires_at, attempts FROM otp_store WHERE email = ${email}`;
  if (!rows.length) return null;
  return { otp: rows[0].otp, expires: new Date(rows[0].expires_at).getTime(), attempts: rows[0].attempts };
}

async function setOtp(email, { otp, expires, attempts }) {
  await ensureTables();
  await sql`INSERT INTO otp_store (email, otp, expires_at, attempts)
            VALUES (${email}, ${otp}, ${new Date(expires).toISOString()}, ${attempts})
            ON CONFLICT (email) DO UPDATE SET otp = EXCLUDED.otp, expires_at = EXCLUDED.expires_at, attempts = EXCLUDED.attempts`;
}

async function deleteOtp(email) {
  await ensureTables();
  await sql`DELETE FROM otp_store WHERE email = ${email}`;
}

module.exports = { readDB, writeDB, listBackups, restoreBackup, getOtp, setOtp, deleteOtp, sql };
